```class Solution {
    public String categorizeBox(int length, int width, int height, int mass) {
        if (length >= 1000 || width >= 100 || height >= 100 || mass >= 1000) {
            return "Heavy";
        }

        if (length * width * height >= 1000000) {
            return "Bulky";
        }

        return "Neither";
    }
}
